import { AppBar, Avatar, Box, Drawer, IconButton, List, ListItem, ListItemIcon, ListItemText, makeStyles, Toolbar, Typography } from '@material-ui/core'
import { AddCircle, Dashboard, ExpandMore, PlaylistAddCheck } from '@material-ui/icons';
import urslogo from '../images/urslogo.png'
import phil from '../images/phil.png'
import React from 'react'
import { useHistory } from 'react-router-dom/cjs/react-router-dom.min';


const drawerWidth = 100;

const useStyle = makeStyles(theme => {
    return {
    root: {
        display: 'flex'
    },
    page: {
        background: '#f9fbfd',
        width: '100%',
        padding: theme.spacing(3)
    },
    sidebar: {
        width: drawerWidth
    },
    sidebarSpace: {
        width: drawerWidth,
        background: '#162276',
        color: '#ffffff'
    },
    logoContainer: {
        maxWidth: '40px',
        margin: '2px auto'
    },
    logo: {
        width: '100%',
        paddingTop: '10%'
    },
    appbar: {
        width: `calc(100% - ${drawerWidth}px)`
    },
    toolbar: theme.mixins.toolbar,
    title: {
        flexGrow: 1
    }
}
});


export default function Layout({ children }) {
    const classes = useStyle()
    const history = useHistory()

    const sideLinks = [
        {
            text: 'Dashboard',
            icon: <Dashboard color='error' />,
            path: '/studentDashboard'
        },
        {
            text: 'Subjects',
            icon: <PlaylistAddCheck color='error' />,
            path: '/studentDashboard'
        },
        {
            text: 'Join a Class',
            icon: <AddCircle color='error' />,
            path: '/studentDashboard'
        },
    ]

    return (
        <div className={classes.root}>
            {/* // appbar */}

            <AppBar className={classes.appbar} color='inherit' elevation={2}>
                <Toolbar>
                    <Typography className={classes.title} variant='h5'>
                        URSAC ONLINE 
                    </Typography>
                    <IconButton>
                        <Avatar src={phil}/>
                        </IconButton>
                    <Typography variant='caption'>
                        Cris Philip V. Cajurao
                        <IconButton>
                            <ExpandMore />
                        </IconButton>
                    </Typography>
                </Toolbar>
            </AppBar>

            {/* // sidebar */}

            <Drawer
                className={classes.sidebar}
                variant='permanent'
                anchor='left'
                classes={{ paper: classes.sidebarSpace }}
            >
                <div className={classes.logoContainer}>
                    <Box >
                        <img className={classes.logo} src={urslogo} alt="URSAC Online logo" />
                    </Box>
                </div>
                {/* List links */}
                <List>
                    {sideLinks.map(sideLink => (
                        <ListItem 
                        button 
                        key={sideLink.text}
                        onClick = {() => history.push(sideLink.path)}
                        >
                            
                                <ListItemIcon>
                                    {sideLink.icon}
                                </ListItemIcon>
                                <ListItemText>
                                    {sideLink.text}
                                </ListItemText>
                        </ListItem>
                    ))}
                </List>

            </Drawer>

            <div className={classes.page}>
                <div className={classes.toolbar} elevation={0}></div>
                {children}
            </div>
        </div>
    )
}
